import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r,o as s,c as n,a as h,b as e,d as o,e as p,w as c,f as l}from"./app-248b3437.js";const d={},i=e("p",null,"「They throw their shadows before them who carry their lantern on their back.」——Tagore",-1),u=l('<p>隔离生活告一段落，因为后面忙于应付作业没时间处理日记，索性就作罢，然后觉得单以 “水痘” 开个栏目不妥，于是又捣腾了一下换成了 “日记” 栏目，说是日记，不过我的生活实际上记无可记。</p><p>隔离的日子很难评价，这种独处的时光是令人抓狂的，但时间一长，这种抓狂也毫无意义。</p><p>「哭？哭也是算时间的哦。」（<s>该死的现代性</s>）</p><hr><p>忙活了一天算是把实验报告部分彻底弄完了，长的报告一万多字，最短的也有四五千字，至于为什么花这么多时间在一门 2 学分的通识 PF 课程上，也许是想做吧，今天还专门重新排了一次版，设计了一下样式。</p><p>好吧我承认，这门课我确实没学到什么，实验课令人难以评价。</p><p>「这种古老的实验课模式就应该完蛋。」（<s>小声嘀咕</s>）</p><h2 id="关于博客的更新" tabindex="-1"><a class="header-anchor" href="#关于博客的更新" aria-hidden="true">#</a> 关于博客的更新</h2><p><strong>必须承认的事实是，最近的高产是偶然事件。</strong></p><p>因为没打算很早睡，花了点事件干了一些事：</p><h3 id="首页-logo" tabindex="-1"><a class="header-anchor" href="#首页-logo" aria-hidden="true">#</a> 首页 logo</h3><blockquote><p>听说邪神酱最近新的一季又开播了x</p></blockquote><p>logo 从原来 <strong>V</strong>uepress-theme-<strong>H</strong>ope 的 svg 替换成邪神酱的 png 了，至于最终效果嘛，看着得整个边缘柔化边缘，但懒得上 PS 便直接用 scss 做了，反正也不错那点流量，底部加了个模糊，看着还行x</p><blockquote><p>本来想直接用 box-shadow 欺骗一下视觉的，不过转念一想 box-shadow 没法对非纯色背景起效</p></blockquote><p>研究了一下发现 vuepress-theme-hope 给头图的是空间而不是容器（其实这样设计挺好），于是像 <code>mask</code> 这种东西肯定玩不了了，瞎几把搞了一下最后还是直接用高斯模糊x，看着不锐化就行x</p><h3 id="头图资源过大" tabindex="-1"><a class="header-anchor" href="#头图资源过大" aria-hidden="true">#</a> 头图资源过大</h3><blockquote><p>这个问题的出现单纯是因为我懒得搞x</p></blockquote><p>头图的资源加载问题，因为我真的不想换成，于是折中了一下，给手机设备替换成了另一张只有原来 1/10 的新头图x，PC 设备就自生自灭吧，你们也不差那几 ms 和 kb（repeat × n）。</p><h3 id="字体资源" tabindex="-1"><a class="header-anchor" href="#字体资源" aria-hidden="true">#</a> 字体资源</h3><p>emmm，主要我常用的字体体积都很大，压缩为 base64 都相当大，像仓耳今楷一个字体就 18MB，所以先搁置了这部分。</p><hr><p>2024-01-04 update:</p>',22),_=e("li",null,"修改了文章错漏字，最近几天错漏字有点太多了。",-1),m=e("li",null,"手残删除了两个评论，waline 似乎没有回滚功能，评论字体可以小美化一下，加上引导也很不友好，~~（issue 启动x）~~考完试有时间再处理一下。",-1);function x(b,f){const t=r("RouterLink");return s(),n("div",null,[i,h(" more "),u,e("ul",null,[_,m,e("li",null,[o("添加了一点 Waline 的说明到 "),p(t,{to:"/chat.html"},{default:c(()=>[o("chat")]),_:1}),o(" 页面中")])])])}const w=a(d,[["render",x],["__file","2024-01-02.html.vue"]]);export{w as default};
